"""SFT (Supervised Fine-Tuning) Trainer for orchestrator.

Trains the orchestrator policy using supervised learning on trajectories
generated by the SFT trace generator. Uses both successful and unsuccessful
traces for contrastive learning signal.

Key differences from GRPO:
- No reward model needed - uses pre-generated traces with success labels
- Simpler training loop - standard cross-entropy loss
- Can weight successful traces higher for preference learning
"""

from __future__ import annotations

import json
from dataclasses import dataclass, asdict
from pathlib import Path
from tqdm import trange
from typing import Any, Dict, List, Optional, Iterator

# Optional imports
try:
    import torch
    import torch.nn.functional as F
    from torch.utils.data import Dataset, DataLoader
    HAS_TORCH = True
except ImportError:
    HAS_TORCH = False
    torch = None
    Dataset = object
    DataLoader = None

try:
    from accelerate import Accelerator
    from accelerate.utils import set_seed
    HAS_ACCELERATE = True
except ImportError:
    HAS_ACCELERATE = False
    Accelerator = None

from orchestrator.data import (
    SFTTrace,
    SFTTraceGroup,
    SFTTraceGenerator,
    GeneralThoughtDataset,
    AgentDataCollectionDataset,
    MixedDataset,
    create_mixed_dataset,
    generate_sft_dataset,
)
from orchestrator.training.rl.policy import PolicyModel
from orchestrator.training.sft.sft_evaluator import SFTEvaluator, EvalMetrics


@dataclass
class SFTConfig:
    """Configuration for SFT training."""
    
    # Model
    model_name: str = "Qwen/Qwen3-1.7B"
    max_seq_length: int = 4096
    
    # Training
    num_epochs: int = 3
    batch_size: int = 8
    learning_rate: float = 2e-5
    weight_decay: float = 0.01
    warmup_ratio: float = 0.1
    max_grad_norm: float = 1.0
    
    # Trace generation (successful trajectories only)
    traces_per_query: int = 2
    """Target number of successful traces to generate per query"""
    
    # Dataset mode (GeneralThought + Agent Data Collection)
    dataset_mode: str = "mixed"
    """Dataset mode: 'generalthought', 'agentdata', or 'mixed'"""
    
    dataset_limit: Optional[int] = None
    """Limit samples per dataset"""
    
    # Dataset weights (for mixed mode)
    generalthought_weight: float = 0.5
    """Weight for GeneralThought samples in mixed mode"""
    
    agentdata_weight: float = 0.5
    """Weight for Agent Data samples in mixed mode"""
    
    # GeneralThought specific
    min_verifier_score: float = 0.5
    """Minimum verifier score for GeneralThought quality filtering"""
    
    # Agent Data specific
    agentdata_domains: List[str] = None
    """ADP domains to include"""
    
    # Available tools for trace generation
    available_tools: List[str] = None
    
    # Generation model for creating trajectories
    generation_model: str = "gemini:gemini-2.5-flash"
    """Model to use for generating trajectories (not added as a tool)"""
    
    max_attempts_per_trace: int = 3
    """Max attempts to generate one successful trace"""
    
    generation_temperature: float = 0.7
    """Sampling temperature for generation"""
    
    # Caching
    trace_cache_path: str = "data/sft_traces.jsonl"
    regenerate_traces: bool = False
    """If True, regenerate traces even if cache exists"""
    
    # Checkpointing
    checkpoint_dir: str = "checkpoints/sft"
    save_every_n_epochs: int = 1
    
    # Logging
    log_dir: str = "logs/sft"
    log_every_n_steps: int = 10
    use_wandb: bool = False
    wandb_project: str = "orchestrator-sft"
    
    # Memory optimization
    gradient_checkpointing: bool = True
    gradient_accumulation_steps: int = 1
    
    # Early stopping with evaluation
    early_stopping: bool = False
    """Enable early stopping based on eval task performance"""
    
    early_stopping_patience: int = 3
    """Number of epochs with no improvement before stopping"""
    
    early_stopping_threshold: float = 0.0
    """Minimum improvement to qualify as progress"""
    
    eval_tasks_path: Optional[str] = None
    """Path to evaluation tasks (JSONL or Arrow dataset)"""
    
    max_eval_tasks: int = 100
    """Maximum number of eval tasks to run"""
    
    eval_every_n_epochs: int = 1
    """Evaluate every N epochs"""
    
    def __post_init__(self):
        # Use all ToolOrchestra + ADP tools by default
        if self.available_tools is None:
            from orchestrator.data.sft_trace_generator import get_default_tools
            self.available_tools = get_default_tools()
        
        # Default ADP domains
        if self.agentdata_domains is None:
            self.agentdata_domains = [
                "codeact",
                "agenttuning_alfworld",
                "agenttuning_db",
                "agenttuning_mind2web",
                "agenttuning_webshop",
                "code_feedback",
            ]


class SFTDataset:
    """Dataset for SFT training from generated traces.
    
    Loads traces from JSONL file and provides formatted examples
    for training.
    """
    
    def __init__(
        self,
        trace_path: str,
        tokenizer: Any,
        max_seq_length: int = 4096,
    ):
        """Initialize SFT dataset.
        
        Args:
            trace_path: Path to JSONL file with traces
            tokenizer: Tokenizer for encoding
            max_seq_length: Maximum sequence length
        """
        self.tokenizer = tokenizer
        self.max_seq_length = max_seq_length
        
        self.traces: List[Dict[str, Any]] = []
        
        self._load_traces(trace_path)
    
    def _load_traces(self, trace_path: str):
        """Load traces from JSONL file (all should be successful)."""
        trace_path = Path(trace_path)
        if not trace_path.exists():
            print(f"Warning: Trace file not found: {trace_path}")
            return
        
        with open(trace_path) as f:
            for line in f:
                trace = json.loads(line)
                self.traces.append(trace)
        
        print(f"Loaded {len(self.traces)} successful traces")
    
    def __len__(self) -> int:
        return len(self.traces)
    
    def __getitem__(self, idx: int) -> Dict[str, Any]:
        """Get formatted training example.
        
        Returns tokenized conversation with labels for next-token prediction.
        """
        trace = self.traces[idx]
        
        # Format conversations into training text
        text = self._format_conversation(trace["conversations"])
        
        # Tokenize
        encoding = self.tokenizer(
            text,
            truncation=True,
            max_length=self.max_seq_length,
            padding="max_length",
            return_tensors="pt",
        )
        
        return {
            "input_ids": encoding["input_ids"].squeeze(0),
            "attention_mask": encoding["attention_mask"].squeeze(0),
            "labels": encoding["input_ids"].squeeze(0).clone(),
        }
    
    def _format_conversation(self, conversations: List[Dict[str, str]]) -> str:
        """Format conversation turns into training text.
        
        Supports both formats:
        - New format: {role: "user"/"assistant"/"system"/"tool", content: "..."}
        - Old format: {from: "human"/"gpt", value: "..."}
        """
        # Try to use chat template if available
        if hasattr(self.tokenizer, "apply_chat_template"):
            try:
                messages = []
                for turn in conversations:
                    # Handle both formats
                    role = turn.get("role") or turn.get("from", "")
                    content = turn.get("content") or turn.get("value", "")
                    
                    # Normalize role names
                    if role in ("human", "user"):
                        role = "user"
                    elif role in ("gpt", "assistant"):
                        role = "assistant"
                    elif role == "tool":
                        # Include tool response as user message
                        tool_name = turn.get("name", "tool")
                        content = f"[Tool '{tool_name}' returned]: {content}"
                        role = "user"
                    
                    if role in ("user", "assistant", "system"):
                        messages.append({"role": role, "content": content})
                
                return self.tokenizer.apply_chat_template(
                    messages, tokenize=False, add_generation_prompt=False
                )
            except Exception:
                pass  # Fall through to manual formatting
        
        # Manual formatting fallback
        parts = []
        for turn in conversations:
            role = turn.get("role") or turn.get("from", "")
            content = turn.get("content") or turn.get("value", "")
            
            if role in ("human", "user"):
                parts.append(f"<|user|>\n{content}")
            elif role in ("gpt", "assistant"):
                parts.append(f"<|assistant|>\n{content}")
            elif role == "system":
                parts.append(f"<|system|>\n{content}")
            elif role == "tool":
                tool_name = turn.get("name", "tool")
                parts.append(f"<|user|>\n[Tool '{tool_name}' returned]: {content}")
        
        return "\n".join(parts) + self.tokenizer.eos_token
    
    def iter_batches(self, batch_size: int) -> Iterator[List[Dict[str, Any]]]:
        """Iterate over batches.
        
        Args:
            batch_size: Batch size
            
        Yields:
            Batches of training examples
        """
        batch = []
        for i in range(len(self)):
            batch.append(self[i])
            if len(batch) == batch_size:
                yield batch
                batch = []
        if batch:
            yield batch


class SFTTrainer:
    """SFT trainer for orchestrator.
    
    Example:
        config = SFTConfig(
            model_name="Qwen/Qwen3-1.7B",
            num_epochs=3,
            traces_per_query=4,
        )
        
        trainer = SFTTrainer(config)
        trainer.train()
    """
    
    def __init__(self, config: SFTConfig):
        """Initialize SFT trainer.
        
        Args:
            config: Training configuration
        """
        self.config = config
        
        # Initialize Accelerator for multi-GPU with FSDP
        if HAS_ACCELERATE:
            from accelerate import FullyShardedDataParallelPlugin
            from torch.distributed.fsdp.fully_sharded_data_parallel import FullOptimStateDictConfig, FullStateDictConfig
            
            # Configure FSDP for sharding large models
            fsdp_plugin = FullyShardedDataParallelPlugin(
                state_dict_config=FullStateDictConfig(offload_to_cpu=True, rank0_only=True),
                optim_state_dict_config=FullOptimStateDictConfig(offload_to_cpu=True, rank0_only=True),
            )
            
            self.accelerator = Accelerator(
                gradient_accumulation_steps=config.gradient_accumulation_steps,
                mixed_precision="bf16" if torch.cuda.is_available() else "no",
                fsdp_plugin=fsdp_plugin,
            )
            self.device = self.accelerator.device
            self.is_main_process = self.accelerator.is_main_process
            if self.is_main_process:
                print(f"Using {self.accelerator.num_processes} GPU(s) with FSDP")
        elif HAS_TORCH and torch is not None:
            self.accelerator = None
            self.device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
            self.is_main_process = True
        else:
            self.accelerator = None
            self.device = None
            self.is_main_process = True
        
        if self.is_main_process:
            print("Initializing SFT trainer...")
        self._init_model()
        self._init_data()
        self._init_optimizer()
        self._init_logging()
        self._init_evaluator()
        
        self.global_step = 0
    
    def _init_model(self):
        """Initialize policy model."""
        if self.is_main_process:
            print(f"Loading model: {self.config.model_name}")
        
        # Don't pass device when using Accelerate - it handles placement
        device_str = None if self.accelerator else (str(self.device) if self.device else None)
        
        self.policy = PolicyModel.from_pretrained(
            self.config.model_name,
            max_tokens=self.config.max_seq_length,
            gradient_checkpointing=self.config.gradient_checkpointing,
            device=device_str,
        )
        
        if self.policy.model is not None:
            self.policy.model.train()
    
    def _init_data(self):
        """Initialize dataset - generate or load traces."""
        trace_path = Path(self.config.trace_cache_path)
        
        # Generate traces if needed
        if self.config.regenerate_traces or not trace_path.exists():
            print("Generating SFT traces...")
            self._generate_traces()
        
        # Load trace dataset (use all data for training)
        print(f"Loading traces from {trace_path}")
        self.dataset = SFTDataset(
            trace_path=str(trace_path),
            tokenizer=self.policy.tokenizer,
            max_seq_length=self.config.max_seq_length,
        )
    
    def _generate_traces(self):
        """Generate SFT traces from datasets using MixedDataset.
        
        Uses GeneralThought (reasoning traces) + Agent Data Collection (tool trajectories).
        """
        generalthought_dataset = None
        agentdata_dataset = None
        
        mode = self.config.dataset_mode
        print(f"Loading datasets (mode: {mode})...")
        
        # Load GeneralThought if needed
        if mode in ("generalthought", "mixed"):
            print("  Loading GeneralThought...")
            try:
                generalthought_dataset = GeneralThoughtDataset(
                    split="train",
                    limit=self.config.dataset_limit,
                    min_verifier_score=self.config.min_verifier_score,
                )
                print(f"    Loaded {len(generalthought_dataset)} samples (min_score={self.config.min_verifier_score})")
            except Exception as e:
                print(f"    Warning: Could not load GeneralThought: {e}")
        
        # Load Agent Data Collection if needed
        if mode in ("agentdata", "mixed"):
            print("  Loading Agent Data Collection...")
            try:
                agentdata_dataset = AgentDataCollectionDataset(
                    domains=self.config.agentdata_domains,
                    limit=self.config.dataset_limit,
                )
                print(f"    Loaded {len(agentdata_dataset)} samples")
            except Exception as e:
                print(f"    Warning: Could not load Agent Data: {e}")
        
        # Create mixed dataset
        if mode == "mixed" and generalthought_dataset and agentdata_dataset:
            dataset = create_mixed_dataset(
                generalthought_dataset=generalthought_dataset,
                agentdata_dataset=agentdata_dataset,
                generalthought_weight=self.config.generalthought_weight,
                agentdata_weight=self.config.agentdata_weight,
            )
            samples = list(dataset)
        elif generalthought_dataset:
            samples = list(generalthought_dataset)
        elif agentdata_dataset:
            samples = list(agentdata_dataset)
        else:
            print("Warning: No datasets loaded")
            samples = []
        
        print(f"Total samples for trace generation: {len(samples)}")
        
        # Generate traces - pass as unified samples
        generate_sft_dataset(
            toolscale_samples=samples if samples else None,
            adp_samples=None,  # Already unified via MixedDataset
            available_tools=self.config.available_tools,
            generation_model=self.config.generation_model,
            traces_per_query=self.config.traces_per_query,
            max_attempts_per_trace=self.config.max_attempts_per_trace,
            temperature=self.config.generation_temperature,
            output_path=self.config.trace_cache_path,
        )
    
    def _init_optimizer(self):
        """Initialize optimizer, scheduler, and prepare with Accelerate."""
        if self.policy.model is None or not HAS_TORCH:
            self.optimizer = None
            self.scheduler = None
            self.dataloader = None
            return
        
        self.optimizer = torch.optim.AdamW(
            self.policy.model.parameters(),
            lr=self.config.learning_rate,
            weight_decay=self.config.weight_decay,
        )
        
        # Create DataLoader
        self.dataloader = DataLoader(
            self.dataset,
            batch_size=self.config.batch_size,
            shuffle=True,
            num_workers=0,
            pin_memory=True,
        )
        
        # Compute total training steps for scheduler
        total_steps = len(self.dataloader) * self.config.num_epochs
        warmup_steps = int(total_steps * self.config.warmup_ratio)
        
        # Linear warmup then decay
        def lr_lambda(step):
            if step < warmup_steps:
                return step / max(1, warmup_steps)
            return max(0.0, 1.0 - (step - warmup_steps) / (total_steps - warmup_steps))
        
        self.scheduler = torch.optim.lr_scheduler.LambdaLR(
            self.optimizer, lr_lambda
        )
        
        # Prepare with Accelerate for multi-GPU
        if self.accelerator:
            self.policy.model, self.optimizer, self.dataloader, self.scheduler = \
                self.accelerator.prepare(
                    self.policy.model, self.optimizer, self.dataloader, self.scheduler
                )
    
    def _init_logging(self):
        """Initialize logging."""
        self.log_dir = Path(self.config.log_dir)
        self.log_dir.mkdir(parents=True, exist_ok=True)
        
        self.metrics_history = []
        
        if self.config.use_wandb:
            try:
                import wandb
                wandb.init(
                    project=self.config.wandb_project,
                    config=asdict(self.config),
                )
                self.wandb = wandb
            except ImportError:
                print("Warning: wandb not installed")
                self.wandb = None
        else:
            self.wandb = None
    
    def _init_evaluator(self):
        """Initialize evaluator for early stopping."""
        if self.config.early_stopping and self.config.eval_tasks_path:
            print(f"Initializing evaluator with tasks from {self.config.eval_tasks_path}")
            try:
                # Load MCP tools from the tool registry
                mcp_tools = self._load_mcp_tools_for_eval()

                self.evaluator = SFTEvaluator(
                    eval_tasks_path=self.config.eval_tasks_path,
                    mcp_tools=mcp_tools,
                    max_turns=10,
                    max_eval_tasks=self.config.max_eval_tasks,
                )
            except Exception as e:
                print(f"Warning: Could not initialize evaluator: {e}")
                print("Early stopping will be disabled")
                self.config.early_stopping = False
                self.evaluator = None
        else:
            self.evaluator = None

    def _load_mcp_tools_for_eval(self) -> Dict[str, Any]:
        """Load MCP tools from registry for evaluation.

        Returns:
            Dictionary mapping tool names to MCP server instances.
        """
        try:
            from agents.mcp.tool_registry import get_registry

            registry = get_registry()
            tools = {}

            # Load core utility tools for evaluation
            eval_tools = [
                "calculator",
                "think",
                "code_interpreter",
                "web_search",
            ]

            for tool_name in eval_tools:
                tool_instance = registry.get_tool_instance(tool_name)
                if tool_instance:
                    tools[tool_name] = tool_instance

            print(f"Loaded {len(tools)} MCP tools for evaluation: {list(tools.keys())}")
            return tools

        except ImportError as e:
            print(f"Warning: Could not import tool registry: {e}")
            return {}
        except Exception as e:
            print(f"Warning: Could not load MCP tools: {e}")
            return {}
    
    def train(self):
        """Run SFT training loop with eval-based early stopping."""
        if self.is_main_process:
            print("=" * 70)
            print("Starting SFT Training")
            print("=" * 70)
            print(f"Model: {self.config.model_name}")
            print(f"Dataset: {len(self.dataset)} training traces")
            print(f"Epochs: {self.config.num_epochs}")
            print(f"Batch size: {self.config.batch_size}")
            if self.accelerator:
                print(f"GPUs: {self.accelerator.num_processes}")
            if self.config.early_stopping and self.evaluator:
                print(f"Early stopping: enabled")
                print(f"  Eval tasks: {len(self.evaluator.eval_tasks)}")
                print(f"  Eval every: {self.config.eval_every_n_epochs} epoch(s)")
                print(f"  Patience: {self.config.early_stopping_patience} eval(s)")
            print("=" * 70)
            print()
        
        # Early stopping tracking
        best_success_rate = 0.0
        evals_without_improvement = 0
        best_checkpoint_epoch = -1
        
        epoch_iter = trange(self.config.num_epochs) if self.is_main_process else range(self.config.num_epochs)
        for epoch in epoch_iter:
            if self.is_main_process:
                print(f"\nEpoch {epoch + 1}/{self.config.num_epochs}")
                print("-" * 70)
            
            # Train epoch
            epoch_metrics = self._train_epoch(epoch)
            
            # Save checkpoint
            if (epoch + 1) % self.config.save_every_n_epochs == 0:
                self._save_checkpoint(epoch)
            
            # Evaluation if early stopping enabled
            if self.config.early_stopping and self.evaluator:
                if (epoch + 1) % self.config.eval_every_n_epochs == 0:
                    # Run evaluation on saved checkpoint
                    checkpoint_path = Path(self.config.checkpoint_dir) / f"epoch_{epoch+1}"
                    
                    try:
                        eval_metrics = self.evaluator.evaluate(
                            checkpoint_path=str(checkpoint_path),
                            verbose=False,
                        )
                        
                        epoch_metrics["eval_success_rate"] = eval_metrics.success_rate
                        epoch_metrics["eval_avg_turns"] = eval_metrics.avg_turns
                        
                        # Check for improvement
                        if eval_metrics.success_rate > best_success_rate + self.config.early_stopping_threshold:
                            best_success_rate = eval_metrics.success_rate
                            evals_without_improvement = 0
                            best_checkpoint_epoch = epoch
                            print(f"✓ New best success rate: {eval_metrics.success_rate:.1%}")
                        else:
                            evals_without_improvement += 1
                            print(f"  No improvement for {evals_without_improvement} evaluation(s)")
                            
                            if evals_without_improvement >= self.config.early_stopping_patience:
                                print()
                                print("=" * 70)
                                print(f"Early stopping triggered after {epoch + 1} epochs")
                                print(f"Best success rate: {best_success_rate:.1%} at epoch {best_checkpoint_epoch + 1}")
                                print("=" * 70)
                                break
                    
                    except Exception as e:
                        print(f"Warning: Evaluation failed: {e}")
                        print("Continuing training without eval metrics")
            
            self._log_metrics(epoch_metrics, epoch)
        
        if self.is_main_process:
            print()
            print("=" * 70)
            print("Training complete!")
            if self.config.early_stopping and best_checkpoint_epoch >= 0:
                print(f"Best checkpoint: epoch {best_checkpoint_epoch + 1}")
                print(f"Best success rate: {best_success_rate:.1%}")
            print("=" * 70)
    
    def _train_epoch(self, epoch: int) -> Dict[str, float]:
        """Train for one epoch using DataLoader."""
        if self.policy.model is None or not HAS_TORCH or self.dataloader is None:
            return {"epoch": epoch, "loss": 0.0}
        
        self.policy.model.train()
        
        total_loss = 0.0
        num_batches = 0
        
        for batch in self.dataloader:
            loss = self._train_step(batch)
            
            total_loss += loss
            num_batches += 1
            
            self.global_step += 1
            
            if self.is_main_process and self.global_step % self.config.log_every_n_steps == 0:
                print(f"  Step {self.global_step}: loss={loss:.4f}")
        
        avg_loss = total_loss / num_batches if num_batches > 0 else 0.0
        
        return {
            "epoch": epoch,
            "loss": avg_loss,
            "num_batches": num_batches,
        }
    
    def _train_step(self, batch: Dict[str, torch.Tensor]) -> float:
        """Perform one training step.
        
        Args:
            batch: Dictionary with input_ids, attention_mask, labels
            
        Returns:
            Loss value
        """
        # Move to device (Accelerate handles this if prepared)
        if not self.accelerator:
            input_ids = batch["input_ids"].to(self.device)
            attention_mask = batch["attention_mask"].to(self.device)
            labels = batch["labels"].to(self.device)
        else:
            input_ids = batch["input_ids"]
            attention_mask = batch["attention_mask"]
            labels = batch["labels"]
        
        # Forward pass with gradient accumulation context
        if self.accelerator:
            with self.accelerator.accumulate(self.policy.model):
                outputs = self.policy.model(
                    input_ids=input_ids,
                    attention_mask=attention_mask,
                    labels=labels,
                )
                loss = outputs.loss
                self.accelerator.backward(loss)
                
                # Gradient clipping
                if self.accelerator.sync_gradients:
                    self.accelerator.clip_grad_norm_(
                        self.policy.model.parameters(),
                        self.config.max_grad_norm,
                    )
                
                self.optimizer.step()
                self.scheduler.step()
                self.optimizer.zero_grad()
        else:
            outputs = self.policy.model(
                input_ids=input_ids,
                attention_mask=attention_mask,
                labels=labels,
            )
            loss = outputs.loss
            
            self.optimizer.zero_grad()
            loss.backward()
            
            torch.nn.utils.clip_grad_norm_(
                self.policy.model.parameters(),
                self.config.max_grad_norm,
            )
            
            self.optimizer.step()
            self.scheduler.step()
        
        return loss.item()
    
    def _save_checkpoint(self, epoch: int):
        """Save checkpoint."""
        if not self.is_main_process:
            return
        
        checkpoint_dir = Path(self.config.checkpoint_dir)
        checkpoint_dir.mkdir(parents=True, exist_ok=True)
        
        checkpoint_path = checkpoint_dir / f"epoch_{epoch + 1}"
        
        if self.policy.model is not None:
            # Unwrap model if using Accelerate
            if self.accelerator:
                unwrapped_model = self.accelerator.unwrap_model(self.policy.model)
                unwrapped_model.save_pretrained(str(checkpoint_path))
                if self.policy.tokenizer:
                    self.policy.tokenizer.save_pretrained(str(checkpoint_path))
            else:
                self.policy.save(str(checkpoint_path))
            print(f"Saved checkpoint to {checkpoint_path}")
            
            # Save training state
            state_path = checkpoint_path / "training_state.json"
            state = {
                "epoch": epoch,
                "global_step": self.global_step,
                "config": asdict(self.config),
            }
            with open(state_path, "w") as f:
                json.dump(state, f, indent=2)
    
    def _log_metrics(self, metrics: Dict[str, Any], epoch: int):
        """Log metrics."""
        self.metrics_history.append(metrics)
        
        metrics_file = self.log_dir / "metrics.jsonl"
        with open(metrics_file, "a") as f:
            f.write(json.dumps(metrics) + "\n")
        
        if self.wandb:
            self.wandb.log(metrics, step=self.global_step)
        
        print(f"\nEpoch {epoch + 1} Summary:")
        for key, value in metrics.items():
            if isinstance(value, float):
                print(f"  {key}: {value:.4f}")
            else:
                print(f"  {key}: {value}")


def train_sft(
    model_name: str = "Qwen/Qwen3-1.7B",
    traces_per_query: int = 4,
    num_epochs: int = 3,
    **kwargs,
) -> SFTTrainer:
    """Convenience function to run SFT training.
    
    Args:
        model_name: Model to fine-tune
        traces_per_query: Number of traces per query
        num_epochs: Training epochs
        **kwargs: Additional config options
        
    Returns:
        Trained SFTTrainer instance
    """
    config = SFTConfig(
        model_name=model_name,
        traces_per_query=traces_per_query,
        num_epochs=num_epochs,
        **kwargs,
    )
    
    trainer = SFTTrainer(config)
    trainer.train()
    
    return trainer
